blocks.en:
flowchart TD
  S["Frame at MPNC: read Destination TREEID"] --> C{"In a child's TREEID block?"}
  C -- yes --> D["Forward down to that child"]
  C -- no --> N{"In a neighbor's TREEID block?"}
  N -- yes --> E["Forward sideways to neighbor"]
  N -- no --> P["Forward up to parent"]

blocks.zh:
flowchart TD
  S["帧到达 MPNC：读取目的 TREEID"] --> C{"是否落在某子节点的 TREEID 块内?"}
  C -- 是 --> D["向下转发给该子节点"]
  C -- 否 --> N{"是否落在某邻居的 TREEID 块内?"}
  N -- 是 --> E["横向转发给邻居"]
  N -- 否 --> P["向上转发给父节点"]
